),
"Coverage: Payer Type" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'type') AS "type" FROM resources r WHERE r.resourceType = 'Coverage' AND in_valueset(r.resource, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.114222.4.11.3591')
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"Patient Age 12 Years or Older at Start of Measurement Period" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 12
),
"Patient Age 12 to 16 Years at Start of Measurement Period" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END BETWEEN 12 AND 16
),
"Patient Age 17 Years at Start of Measurement Period" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END = 17
),
"Patient Age 18 Years or Older at Start of Measurement Period" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 18
),
"Qualifying Encounter During Measurement Period" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Encounter to Screen for Depression" UNION SELECT patient_id, resource FROM "Encounter: Physical Therapy Evaluation" UNION SELECT patient_id, resource FROM "Encounter: Telephone Visits") AS QualifyingEncounter WHERE CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(intervalEnd(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND fhirpath_text(QualifyingEncounter.resource, 'status') = 'finished'
),
"Has Adolescent Depression Screening" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Observation: Adolescent depression screening assessment" AS AdolescentScreening WHERE AdolescentScreening.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Qualifying Encounter During Measurement Period") AS QualifyingEncounter WHERE CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) - INTERVAL '14 day' <= CAST(intervalStart(CASE WHEN fhirpath_text(AdolescentScreening.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AdolescentScreening.resource, 'effective')), '{') THEN fhirpath_text(AdolescentScreening.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(AdolescentScreening.resource, 'effective'), fhirpath_text(AdolescentScreening.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(AdolescentScreening.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AdolescentScreening.resource, 'effective')), '{') THEN fhirpath_text(AdolescentScreening.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(AdolescentScreening.resource, 'effective'), fhirpath_text(AdolescentScreening.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) AND fhirpath_text(AdolescentScreening.resource, 'value') IS NOT NULL AND array_contains(['final', 'corrected'], fhirpath_text(AdolescentScreening.resource, 'status')) AND QualifyingEncounter.patient_id = AdolescentScreening.patient_id))
),
"Has Adult Depression Screening" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Observation: Adult depression screening assessment" AS AdultScreening WHERE AdultScreening.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Qualifying Encounter During Measurement Period") AS QualifyingEncounter WHERE CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) - INTERVAL '14 day' <= CAST(intervalStart(CASE WHEN fhirpath_text(AdultScreening.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AdultScreening.resource, 'effective')), '{') THEN fhirpath_text(AdultScreening.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(AdultScreening.resource, 'effective'), fhirpath_text(AdultScreening.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(AdultScreening.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AdultScreening.resource, 'effective')), '{') THEN fhirpath_text(AdultScreening.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(AdultScreening.resource, 'effective'), fhirpath_text(AdultScreening.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) AND fhirpath_text(AdultScreening.resource, 'value') IS NOT NULL AND array_contains(['final', 'corrected'], fhirpath_text(AdultScreening.resource, 'status')) AND QualifyingEncounter.patient_id = AdultScreening.patient_id))
),
"History of Bipolar Diagnosis Before Qualifying Encounter" AS (
SELECT * FROM "Condition: Bipolar Disorder (qicore-condition-problems-health-concerns)" AS BipolarDiagnosis WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Qualifying Encounter During Measurement Period") AS QualifyingEncounter WHERE CAST(intervalStart(CASE WHEN fhirpath_text(BipolarDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(BipolarDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BipolarDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BipolarDiagnosis.resource, 'recordedDate')), fhirpath_text(BipolarDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(BipolarDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BipolarDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BipolarDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(BipolarDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(BipolarDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BipolarDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BipolarDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(BipolarDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BipolarDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BipolarDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) AND QualifyingEncounter.patient_id = BipolarDiagnosis.patient_id)
),
"Denominator Exclusions" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "History of Bipolar Diagnosis Before Qualifying Encounter" AS sub WHERE sub.patient_id = p.patient_id)
),
"Initial Population" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Patient Age 12 Years or Older at Start of Measurement Period" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "Qualifying Encounter During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id)
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"Medical or Patient Reason for Not Screening Adolescent for Depression" AS (
SELECT * FROM "Observation: Adolescent depression screening assessment (observationcancelled)" AS NoAdolescentScreen WHERE (fhirpath_bool(NoAdolescentScreen.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-notDoneReason'').value.coding.where(system=''http://snomed.info/sct'' and code=''720834000'').exists()') OR in_valueset(NoAdolescentScreen.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-notDoneReason'').valueCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1007')) AND EXISTS (SELECT 1 FROM (SELECT * FROM "Qualifying Encounter During Measurement Period") AS QualifyingEncounter WHERE CAST(fhirpath_text(NoAdolescentScreen.resource, 'issued') AS DATE) >= CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) AND CAST(fhirpath_text(NoAdolescentScreen.resource, 'issued') AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND QualifyingEncounter.patient_id = NoAdolescentScreen.patient_id)
),
"Medical or Patient Reason for Not Screening Adult for Depression" AS (
