"Most Recent Adult Depression Screening Positive and Follow Up Provided" AS (
SELECT p.patient_id, (SELECT resource FROM "Most Recent Adult Depression Screening" AS LastAdultScreen WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Follow Up Intervention for Positive Adult Depression Screening") AS FollowUpPositiveAdultScreen CROSS JOIN (SELECT * FROM "Qualifying Encounter During Measurement Period") AS QualifyingEncounter WHERE CAST(CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) - INTERVAL '14 day' AS DATE) <= CAST(intervalStart(CASE WHEN fhirpath_text(LastAdultScreen.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(LastAdultScreen.resource, 'effective')), '{') THEN fhirpath_text(LastAdultScreen.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(LastAdultScreen.resource, 'effective'), fhirpath_text(LastAdultScreen.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(LastAdultScreen.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(LastAdultScreen.resource, 'effective')), '{') THEN fhirpath_text(LastAdultScreen.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(LastAdultScreen.resource, 'effective'), fhirpath_text(LastAdultScreen.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= CAST(CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) AS DATE) AND fhirpath_bool(LastAdultScreen.resource, 'value.coding.where(system=''http://snomed.info/sct'' and code=''428181000124104'').exists()') AND (intervalContains(fhirpath_text(QualifyingEncounter.resource, 'period'), intervalStart(CASE WHEN fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed')), '{') THEN fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed'), fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed'), TRUE, TRUE) END)) OR CAST(intervalEnd(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) <= CAST(fhirpath_text(FollowUpPositiveAdultScreen.resource, 'authoredOn') AS DATE) AND CAST(fhirpath_text(FollowUpPositiveAdultScreen.resource, 'authoredOn') AS DATE) <= CAST(intervalEnd(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) + INTERVAL '2 day') AND CAST(COALESCE(intervalStart(CASE WHEN fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed')), '{') THEN fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed'), fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed'), TRUE, TRUE) END), fhirpath_text(FollowUpPositiveAdultScreen.resource, 'authoredOn')) AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(COALESCE(intervalStart(CASE WHEN fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed')), '{') THEN fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed'), fhirpath_text(FollowUpPositiveAdultScreen.resource, 'performed'), TRUE, TRUE) END), fhirpath_text(FollowUpPositiveAdultScreen.resource, 'authoredOn')) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND FollowUpPositiveAdultScreen.patient_id = LastAdultScreen.patient_id AND QualifyingEncounter.patient_id = LastAdultScreen.patient_id) AND LastAdultScreen.patient_id = p.patient_id LIMIT 1) AS resource FROM _patients AS p
),
"Numerator" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Patient Age 12 to 16 Years at Start of Measurement Period" AS sub WHERE sub.patient_id = p.patient_id) AND (EXISTS (SELECT 1 FROM "Has Most Recent Adolescent Screening Negative" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Most Recent Adolescent Depression Screening Positive and Follow Up Provided" AS sub WHERE sub.patient_id = p.patient_id AND sub.resource IS NOT NULL)) OR EXISTS (SELECT 1 FROM "Patient Age 17 Years at Start of Measurement Period" AS sub WHERE sub.patient_id = p.patient_id) AND (EXISTS (SELECT 1 FROM "Has Most Recent Adolescent Screening Negative" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Most Recent Adolescent Depression Screening Positive and Follow Up Provided" AS sub WHERE sub.patient_id = p.patient_id AND sub.resource IS NOT NULL) OR EXISTS (SELECT 1 FROM "Has Most Recent Adult Screening Negative" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Most Recent Adult Depression Screening Positive and Follow Up Provided" AS sub WHERE sub.patient_id = p.patient_id AND sub.resource IS NOT NULL)) OR EXISTS (SELECT 1 FROM "Patient Age 18 Years or Older at Start of Measurement Period" AS sub WHERE sub.patient_id = p.patient_id) AND (EXISTS (SELECT 1 FROM "Has Most Recent Adult Screening Negative" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Most Recent Adult Depression Screening Positive and Follow Up Provided" AS sub WHERE sub.patient_id = p.patient_id AND sub.resource IS NOT NULL))
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusions", (SELECT CASE WHEN "Denominator Exceptions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exceptions", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Denominator Exceptions" ON p.patient_id = "Denominator Exceptions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
